Leccion 5 · Bucles anidados::5.solutionCode:
function collectEvenNumbers(limit) {
  const result = [];

  for (let value = 0; value <= limit; value += 1) {
    if (value % 2 === 0) {
      result.push(value);
    }
  }

  return result;
}

