Leccion 5 · Closures::5.solutionCode:
function composePipeline(value, steps) {
  return steps.reduce((current, step) => {
    if (step === "trim") return current.trim();
    if (step === "upper") return current.toUpperCase();
    if (step === "suffix-js") return `${current}-js`;
    return current;
  }, value);
}

